    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0x839622D0435D2341ULL + 0xAE1DF92DF90C5983ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseA(pNonce * 0xA896E66E292251A1ULL + 0x9613658F12EED3C7ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0xF64289C08E70BC05ULL + 0xF9499514C8191055ULL);
