    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0xF551673A3F93FC91ULL + 0xA39AA3DF25B466D5ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xB22CDAFED225519FULL + 0x8810CE16495D4611ULL);
