            aOrbiterF = RotL64((aOrbiterF * 3009081009044782443U), 43U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterK) + 9209505304067579944U;
            aOrbiterC = (aOrbiterC ^ aOrbiterH) ^ 3522631966146762306U;
            aOrbiterC = RotL64((aOrbiterC * 3441982898533162599U), 53U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterG) + 8811497120829041188U;
            aOrbiterB = (aOrbiterB ^ aOrbiterI) ^ 14707301680850257294U;
            aOrbiterB = RotL64((aOrbiterB * 11383709499376464085U), 47U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterJ) + 10080595991787801029U;
            aOrbiterH = (aOrbiterH ^ aOrbiterA) ^ 6822892187784299166U;
            aOrbiterH = RotL64((aOrbiterH * 7417016898027778287U), 5U);
            //
            aOrbiterF = (((aOrbiterF + aOrbiterB) + 1981637172055758689U) + aOrbiterUpdateSaltF[((aIndex + 19U)) & S_SALT1]) + aNonceWordA;
            aOrbiterD = ((aOrbiterD ^ aOrbiterF) ^ 16463077485583119324U) ^ aOrbiterUpdateSaltD[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 2876782050665869121U), 39U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 8383837717361569465U;
            aOrbiterG = ((aOrbiterG ^ aOrbiterE) ^ 2788511294985017326U) ^ aOrbiterUpdateSaltA[((aIndex + 4U)) & S_SALT1];
