            //
            aOrbiterD = (aOrbiterD + aOrbiterE) + 7469160295100147267U;
            aOrbiterI = ((aOrbiterI ^ aOrbiterD) ^ 16973986572163482061U) ^ aOrbiterUpdateSaltB[((aIndex + 23U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 15660743778376905023U), 11U);
