            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererC = aWandererC + ((((RotL64(aPrevious, 30U) + aOrbiterB) + RotL64(aOrbiterD, 11U)) + RotL64(aCarry, 11U)) + aNonceWordK);
            aWandererK = aWandererK ^ ((RotL64(aScatter, 53U) + aOrbiterC) + RotL64(aOrbiterE, 43U));
